body.script:
var main = document.getElementById('text');
var polygon = document.getElementById('polygon');
var neirong = document.getElementById('neirong');
function init() 
     main.textContent='标签名11'
};
var data = [{
    label: '标签名1',
},{
    label: '标签名2'
}];

function createTag(tag,objAttr){   
    var svgNS='http://www.w3.org/2000/svg'; 
    var oTag = document.createElementNS(svgNS , tag);    
    for(let attr in objAttr){
        oTag.setAttribute(attr , objAttr[attr]);
    }    
    return oTag;
};
function createElement(index) {
   var svg = createTag("svg",{class: 'data', y: '0'});
   svg.setAttribute('y', (index+1)*10);
   var rect1 = createTag("rect",{width:'100',height:'20',style:'fill:rgb(239, 239, 239); stroke: #ccc; stroke-width: 1;'});
   var text1 = createTag("text", {class:'text', x:'48',y:'11'});
   text1.textContent = data[index].label;
   var rect2 = createTag("rect",{width:'18',x:'1',y:'1',height:'18',style:'fill: rgb(239, 239,1);'});
   var text2 = createTag("text", {class:'text', x:'9', y:'11'});
   text2.textContent = index+1;
   svg.appendChild(rect1);
   svg.appendChild(text1);
   svg.appendChild(rect2);
   svg.appendChild(text2);
   neirong.appendChild(svg);
};
polygon.onclock = function () {
    init();
    for(let i=0; i < data.length; i++){
        createElement(i);
    }
};
